function linprog(c,A,b,bounds){var m=A.length,nO=c.length;var lb=bounds.map(function(x){return x[0]||0;});var ub=bounds.map(function(x){return(x[1]!=null&&x[1]<1e20)?x[1]:1e30;});var bS=new Float64Array(m);for(var i=0;i<m;i++){bS[i]=b[i];for(var j=0;j<nO;j++)bS[i]-=A[i][j]*lb[j];}var ubR=[];for(var j=0;j<nO;j++)if(ub[j]<1e29){var r=new Array(nO).fill(0);r[j]=1;ubR.push({r:r,rhs:ub[j]-lb[j]});}var M=m+ubR.length;var bA=new Float64Array(M);var AA=[];for(var i=0;i<m;i++){bA[i]=bS[i];AA.push(A[i].slice());}for(var e=0;e<ubR.length;e++){bA[m+e]=ubR[e].rhs;AA.push(ubR[e].r.slice());}var nArt=0;for(var i=0;i<M;i++)if(bA[i]<-1e-15)nArt++;var nS=M,nV=nO+nS+nArt,BM=1e8;var tab=[];var basis=new Int32Array(M);var ai=0;for(var i=0;i<M;i++){var row=new Float64Array(nV+1);if(bA[i]<-1e-15){for(var j=0;j<nO;j++)row[j]=-AA[i][j];row[nO+i]=-1;row[nO+nS+ai]=1;row[nV]=-bA[i];basis[i]=nO+nS+ai;ai++;}else{for(var j=0;j<nO;j++)row[j]=AA[i][j];row[nO+i]=1;row[nV]=bA[i];basis[i]=nO+i;}tab.push(row);}var obj=new Float64Array(nV+1);for(var j=0;j<nO;j++)obj[j]=c[j];for(var a=0;a<nArt;a++)obj[nO+nS+a]=BM;for(var i=0;i<M;i++)if(basis[i]>=nO+nS){for(var j=0;j<=nV;j++)obj[j]-=BM*tab[i][j];}for(var it=0;it<15000;it++){var pC=-1,best=-1e-10;for(var j=0;j<nV;j++)if(obj[j]<best){best=obj[j];pC=j;}if(pC<0)break;var pR=-1,minR=Infinity;for(var i=0;i<M;i++)if(tab[i][pC]>1e-12){var r=tab[i][nV]/tab[i][pC];if(r<minR-1e-12){minR=r;pR=i;}}if(pR<0)break;var pv=tab[pR][pC];for(var j=0;j<=nV;j++)tab[pR][j]/=pv;for(var i=0;i<M;i++){if(i===pR)continue;var f=tab[i][pC];if(Math.abs(f)<1e-15)continue;for(var j=0;j<=nV;j++)tab[i][j]-=f*tab[pR][j];}var f2=obj[pC];for(var j=0;j<=nV;j++)obj[j]-=f2*tab[pR][j];basis[pR]=pC;}var ok=true;for(var i=0;i<M;i++)if(basis[i]>=nO+nS&&tab[i][nV]>1e-6)ok=false;var x=new Float64Array(nO);for(var i=0;i<M;i++)if(basis[i]<nO)x[basis[i]]=Math.max(0,tab[i][nV]);for(var j=0;j<nO;j++)x[j]+=lb[j];return{x:x,ok:ok};}
function deaCRS(X,Y){var n=X.length,m=X[0].length,s=Y[0].length,eff=new Float64Array(n);for(var i=0;i<n;i++){var nv=1+n,cc=new Array(nv).fill(0);cc[0]=1;var AA=[],bb=[];for(var k=0;k<m;k++){var r=new Array(nv).fill(0);r[0]=-X[i][k];for(var j=0;j<n;j++)r[1+j]=X[j][k];AA.push(r);bb.push(0);}for(var l=0;l<s;l++){var r=new Array(nv).fill(0);for(var j=0;j<n;j++)r[1+j]=-Y[j][l];AA.push(r);bb.push(-Y[i][l]);}var bnd=[[0,1]];for(var j=0;j<n;j++)bnd.push([0,null]);var res=linprog(cc,AA,bb,bnd);eff[i]=res.ok?Math.max(Math.min(res.x[0],1),0):1;if(isNaN(eff[i]))eff[i]=1;}return eff;}
function deaVRS(X,Y){var n=X.length,m=X[0].length,s=Y[0].length,eff=new Float64Array(n);for(var i=0;i<n;i++){var nv=1+n,cc=new Array(nv).fill(0);cc[0]=1;var AA=[],bb=[];for(var k=0;k<m;k++){var r=new Array(nv).fill(0);r[0]=-X[i][k];for(var j=0;j<n;j++)r[1+j]=X[j][k];AA.push(r);bb.push(0);}for(var l=0;l<s;l++){var r=new Array(nv).fill(0);for(var j=0;j<n;j++)r[1+j]=-Y[j][l];AA.push(r);bb.push(-Y[i][l]);}var r1=new Array(nv).fill(0);for(var j=0;j<n;j++)r1[1+j]=1;AA.push(r1);bb.push(1);var r2=new Array(nv).fill(0);for(var j=0;j<n;j++)r2[1+j]=-1;AA.push(r2);bb.push(-1);var bnd=[[0,1]];for(var j=0;j<n;j++)bnd.push([0,null]);var res=linprog(cc,AA,bb,bnd);eff[i]=res.ok?Math.max(Math.min(res.x[0],1),0):1;if(isNaN(eff[i]))eff[i]=1;}return eff;}
