function Hist({values,title,color,h}){var cl=color||"#4f46e5";var ht=h||175;var valid=(values||[]).filter(function(v){return v!=null&&!isNaN(v)&&isFinite(v);});if(!valid.length)return null;var bins=14,mn=Math.min.apply(null,valid),mx=Math.max.apply(null,valid),rng=mx-mn||1;var bw=rng/bins,counts=new Array(bins).fill(0);valid.forEach(function(v){counts[Math.min(Math.floor((v-mn)/bw),bins-1)]++;});var maxC=Math.max.apply(null,counts.concat([1])),W=480,barW=(W-60)/bins;return (<div style={{marginBottom:20}}><div style={{fontSize:13,fontWeight:600,color:"#1a1d29",marginBottom:8}}>{title}</div><svg width={W} height={ht+30} style={{display:'block'}}>{counts.map(function(c,i){var bh=(c/maxC)*(ht-20),x=40+i*barW;return (<g key={i}><rect x={x} y={ht-bh} width={barW-2} height={bh} rx={2} fill={cl} opacity={0.85}/>{c>0&&<text x={x+barW/2} y={ht-bh-3} textAnchor="middle" fontSize={8} fill="#6b7194">{c}</text>}</g>);})}<line x1={38} y1={ht} x2={W} y2={ht} stroke="#e2e5f1"/><text x={42} y={ht+13} fontSize={8} fill="#6b7194">{mn.toFixed(2)}</text><text x={W-10} y={ht+13} fontSize={8} fill="#6b7194" textAnchor="end">{mx.toFixed(2)}</text></svg></div>);}
