function Tbl({columns,data,pp}){var perPage=pp||18;var[pg,setPg]=useState(0);var pages=Math.ceil(data.length/perPage);var slice=data.slice(pg*perPage,(pg+1)*perPage);return (<div style={{overflowX:'auto',marginBottom:14}}><table style={{width:'100%',borderCollapse:'collapse',fontSize:12,fontFamily:'monospace'}}><thead><tr>{columns.map(function(c,i){return (<th key={i} style={{padding:'8px 10px',background:'#2E5090',color:'#fff',fontWeight:600,textAlign:'left',whiteSpace:'nowrap',fontSize:11}}>{c.label||c.key}</th>);})}</tr></thead><tbody>{slice.map(function(row,ri){return (<tr key={ri} style={{background:ri%2===0?'#fff':'#f3f4f8'}}>{columns.map(function(c,ci){var val=row[c.key];var dec=c.dec!=null?c.dec:3;return (<td key={ci} style={{padding:'6px 10px',borderBottom:'1px solid #e2e5f1',whiteSpace:'nowrap'}}>{typeof val==='number'?val.toFixed(dec):(val!=null?val:'')}</td>);})}</tr>);})}</tbody></table>{pages>1&&(<div style={{display:'flex',gap:6,marginTop:8,alignItems:'center',justifyContent:'center'}}><button onClick={function(){setPg(Math.max(0,pg-1));}} disabled={pg===0} style={{padding:'4px 12px',borderRadius:6,border:'1px solid #e2e5f1',background:'#fff',cursor:'pointer',fontSize:11,opacity:pg===0?0.4:1}}>Prev</button><span style={{fontSize:12,color:'#6b7194'}}>Page {pg+1} of {pages}</span><button onClick={function(){setPg(Math.min(pages-1,pg+1));}} disabled={pg>=pages-1} style={{padding:'4px 12px',borderRadius:6,border:'1px solid #e2e5f1',background:'#fff',cursor:'pointer',fontSize:11,opacity:pg>=pages-1?0.4:1}}>Next</button></div>)}</div>);}
